<?php
use App\Http\Controllers\Admin\CampaignVerificationController; use App\Http\Controllers\Admin\DonationVerificationController; use App\Http\Controllers\CampaignController; use App\Http\Controllers\CertificateController; use App\Http\Controllers\DashboardController; use App\Http\Controllers\Fundraiser\CampaignController as FundraiserCampaignController; use App\Http\Controllers\HomeController; use Illuminate\Support\Facades\Route;
use App\Http\Controllers\Admin\DashboardController as AdminDashboardController;
Route::middleware('throttle:60,1')->group(function(){ Route::get('/', HomeController::class)->name('home'); Route::get('/campaigns', [CampaignController::class,'index'])->name('campaigns.index'); Route::get('/campaigns/{slug}', [CampaignController::class,'show'])->name('campaigns.show'); Route::post('/campaigns/{campaign}/donate', [CampaignController::class,'donate'])->name('campaigns.donate')->middleware('throttle:10,1'); });
Route::middleware(['auth','throttle:120,1'])->group(function(){ Route::get('/dashboard', AdminDashboardController::class)->name('dashboard'); Route::get('/certificates/{certificate}/download',[CertificateController::class,'download'])->name('certificates.download'); Route::middleware('role:fundraiser,admin')->prefix('fundraiser')->name('fundraiser.')->group(function(){ Route::resource('campaigns', FundraiserCampaignController::class)->except(['show','destroy']); }); Route::middleware('role:admin')->prefix('admin')->name('admin.')->group(function(){ Route::get('campaigns',[CampaignVerificationController::class,'index'])->name('campaigns.index'); Route::patch('campaigns/{campaign}/verify',[CampaignVerificationController::class,'verify'])->name('campaigns.verify'); Route::get('donations',[DonationVerificationController::class,'index'])->name('donations.index'); Route::patch('donations/{donation}/verify',[DonationVerificationController::class,'verify'])->name('donations.verify'); Route::post('certificates/{certificate}/email',[CertificateController::class,'email'])->name('certificates.email'); }); });
require __DIR__.'/auth.php';
